import React from 'react';
import Iframe from 'react-iframe';

function GameIFrame({ title, embed, maxWidth }) {
  const aspectRatio = 1;
  const maxHeight = maxWidth * aspectRatio;

  window.coi = {
    shouldRegister: () => !reloadedBySelf,
    shouldDeregister: () => false,
    coepCredentialless: () => true,
    coepDegrade: () => true,
    doReload: () => window.location.reload(),
    quiet: false
  }

  return (
      <div className="card">
        <div className="card-body">
          <div style={{ position: 'relative', paddingTop: `${100 / aspectRatio}%`, maxWidth }}>
            <Iframe
              frameborder="0"
              src={embed}
              title={title}
              width="100%"
              height={maxHeight}
              allowfullscreen=""
            ></Iframe>
          </div>
        </div>
      </div>
  );
};

export default GameIFrame;
